// 设置输出为HTML格式
const invoiceData = $('Code in JavaScript').first().json

// 创建HTML模板
const htmlContent = `
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>发票详情 - ${invoiceData.title}</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'Segoe UI', 'Microsoft YaHei', sans-serif;
        }

        body {
            background-color: #f8f9fa;
            padding: 20px;
            color: #333;
            line-height: 1.6;
        }

        .invoice-container {
            max-width: 800px;
            margin: 0 auto;
            background: white;
            border-radius: 12px;
            box-shadow: 0 5px 20px rgba(0, 0, 0, 0.08);
            overflow: hidden;
        }

        .invoice-header {
            background: linear-gradient(135deg, #1a73e8, #0d47a1);
            color: white;
            padding: 30px 40px;
            text-align: center;
        }

        .invoice-header h1 {
            font-size: 28px;
            font-weight: 600;
            margin-bottom: 8px;
            letter-spacing: 1px;
        }

        .invoice-header .invoice-number {
            font-size: 16px;
            opacity: 0.9;
            font-weight: 300;
        }

        .invoice-body {
            padding: 40px;
        }

        .section-title {
            font-size: 18px;
            font-weight: 600;
            color: #1a73e8;
            margin-bottom: 20px;
            padding-bottom: 10px;
            border-bottom: 2px solid #e8f0fe;
            display: flex;
            align-items: center;
        }

        .section-title i {
            margin-right: 10px;
            font-size: 20px;
        }

        .info-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
            gap: 25px;
            margin-bottom: 35px;
        }

        .info-card {
            background: #f8f9fa;
            border-radius: 10px;
            padding: 20px;
            border-left: 4px solid #1a73e8;
            transition: transform 0.2s, box-shadow 0.2s;
        }

        .info-card:hover {
            transform: translateY(-3px);
            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.05);
        }

        .info-label {
            font-size: 14px;
            color: #666;
            margin-bottom: 8px;
            font-weight: 500;
        }

        .info-value {
            font-size: 18px;
            font-weight: 600;
            color: #222;
        }

        .highlight-card {
            background: linear-gradient(135deg, #e8f0fe, #f1f8ff);
            border-radius: 10px;
            padding: 25px;
            margin-top: 20px;
            border: 1px solid #d2e3fc;
        }

        .amount-display {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-top: 10px;
        }

        .amount-label {
            font-size: 16px;
            color: #555;
        }

        .amount-value {
            font-size: 24px;
            font-weight: 700;
            color: #1a73e8;
        }

        .tax-info {
            display: flex;
            justify-content: space-between;
            margin-top: 15px;
            padding-top: 15px;
            border-top: 1px dashed #ddd;
        }

        .invoice-footer {
            padding: 25px 40px;
            background-color: #f8f9fa;
            text-align: center;
            color: #666;
            font-size: 14px;
            border-top: 1px solid #eee;
        }

        .logo {
            font-weight: 700;
            color: #1a73e8;
            font-size: 18px;
            margin-bottom: 5px;
        }

        /* 响应式设计 */
        @media (max-width: 768px) {
            .invoice-header, .invoice-body, .invoice-footer {
                padding: 25px 20px;
            }

            .info-grid {
                grid-template-columns: 1fr;
            }
        }

        /* 打印样式 */
        @media print {
            body {
                background: white;
                padding: 0;
            }

            .invoice-container {
                box-shadow: none;
                max-width: 100%;
            }
        }
    </style>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css">
</head>
<body>
    <div class="invoice-container">
        <div class="invoice-header">
            <h1>${invoiceData.title}</h1>
            <div class="invoice-number">发票号码: ${invoiceData.invoiceNumber}</div>
        </div>

        <div class="invoice-body">
            <div class="section-title">
                <i class="fas fa-file-invoice"></i> 发票基本信息
            </div>

            <div class="info-grid">
                <div class="info-card">
                    <div class="info-label">发票标题</div>
                    <div class="info-value">${invoiceData.title}</div>
                </div>

                <div class="info-card">
                    <div class="info-label">发票号码</div>
                    <div class="info-value">${invoiceData.invoiceNumber}</div>
                </div>

                <div class="info-card">
                    <div class="info-label">开票日期</div>
                    <div class="info-value">${invoiceData.issueDate}</div>
                </div>

                <div class="info-card">
                    <div class="info-label">开票人</div>
                    <div class="info-value">${invoiceData.issuer}</div>
                </div>
            </div>

            <div class="section-title">
                <i class="fas fa-building"></i> 开票公司信息
            </div>

            <div class="info-grid">
                <div class="info-card">
                    <div class="info-label">开票公司</div>
                    <div class="info-value">${invoiceData.sellerName}</div>
                </div>

                <div class="info-card">
                    <div class="info-label">开票公司税号</div>
                    <div class="info-value">${invoiceData.sellerTaxId}</div>
                </div>
            </div>

            <div class="section-title">
                <i class="fas fa-shopping-cart"></i> 消费信息
            </div>

            <div class="highlight-card">
                <div class="info-label">消费项目</div>
                <div class="info-value" style="margin-bottom: 20px;">${invoiceData.itemName}</div>

                <div class="amount-display">
                    <div class="amount-label">消费金额 (不含税)</div>
                    <div class="amount-value">¥${invoiceData.amountWithoutTax.toFixed(2)}</div>
                </div>

                <div class="tax-info">
                    <div>
                        <div class="info-label">税率</div>
                        <div class="info-value">${invoiceData.taxRate * 100}%</div>
                    </div>

                    <div>
                        <div class="info-label">税额</div>
                        <div class="info-value">¥${invoiceData.taxAmount.toFixed(2)}</div>
                    </div>

                    <div>
                        <div class="info-label">价税合计</div>
                        <div class="info-value" style="color: #1a73e8;">¥${invoiceData.grandTotal.toFixed(2)}</div>
                    </div>
                </div>
            </div>
        </div>

        <div class="invoice-footer">
            <div class="logo">电子发票系统</div>
            <div>本发票由系统自动生成，具有法律效力</div>
            <div style="margin-top: 8px; font-size: 12px;">生成时间: ${new Date().toLocaleString('zh-CN')}</div>
        </div>
    </div>
</body>
</html>
`;

// 返回HTML内容
return [{ json: { htmlContent, ...invoiceData } }];

